#!/usr/bin/env bash
# Generated by test-suite-generator/0.1.0
# Source: ../../iter-1-step3-attempt-2-artifacts/done_when.yaml
# Threshold pulled from done_when.yaml: mutation_kill_rate >= 0.70
#
# Anti-reward-hacking gate (iron rule #5):
# If you bypass this script, you re-open the reward-hacking hole that the
# done_when pipeline closes. Coverage ≥ 0.80 alone is gameable with
# `assert True`; mutation kill rate is the gate that closes that loop.

set -euo pipefail

THRESHOLD=70  # percent — corresponds to thresholds.mutation_kill_rate (>= 0.70)

# Run the mutation suite (slow — minutes to hours; do NOT run in the inner
# dev loop. Pre-merge CI or nightly is appropriate).
mutmut run

RESULT=$(mutmut results | tail -1)
# mutmut output format: "killed: N, survived: M, ..."
KILLED=$(echo "$RESULT" | grep -oP 'killed:\s*\K\d+')
SURVIVED=$(echo "$RESULT" | grep -oP 'survived:\s*\K\d+')
TOTAL=$((KILLED + SURVIVED))
if [[ $TOTAL -eq 0 ]]; then
  echo "ERROR: no mutants generated — likely a path/runner config issue."
  exit 1
fi
SCORE=$(( KILLED * 100 / TOTAL ))
echo "Kill rate: $SCORE% ($KILLED / $TOTAL)"
if [[ $SCORE -lt $THRESHOLD ]]; then
  echo "✗ Below threshold $THRESHOLD%"
  echo "Surviving mutants (the missing tests are in here):"
  mutmut results | grep -E '^(survived|timeout)' | head -20
  exit 1
fi
echo "✓ Kill rate above $THRESHOLD%"
